#include <stdio.h>
#define MIN(a,b) a < b ? a : b
void myprint(long long);
int main() {
	int t[3][3];
	int i, j;
	int n;
	long long cost[3][3][41];
	for(i = 0; i < 3; i++) {
		for(j = 0; j < 3; j++) {
			scanf("%d", &t[i][j]);
		}
	}
	scanf("%d", &n);

	for(i = 0; i < 3; i++) {
		for(j = 0; j < 3; j++) {
			if(i == j)
				cost[i][j][1] = 0;
			else {
				int k = 3 - ( i + j );
				cost[i][j][1] = MIN(t[i][j], t[i][k] + t[k][j]);
			}
		}
	}
	int nn;
	for(nn = 2; nn <= n ; nn++) {
		for(i = 0; i < 3; i++) {
			for(j = 0; j < 3; j++) {
				if(i == j)
					cost[i][j][nn] = 0;
				else {
					int k = 3 - ( i + j );
					cost[i][j][nn] = MIN(
											cost[i][k][nn-1] + cost[k][j][nn-1] + t[i][j],
											cost[i][j][nn-1] + t[i][k] + cost[j][i][nn-1] + t[k][j] + cost[i][j][nn-1]
										);
				}
			}
		}
		for(i = 0; i < 3; i++) {
			for(j = 0; j < 3; j++) {
				if(i != j) {
					int k = 3 - (i + j);
					cost[i][j][nn] = MIN(cost[i][j][nn], cost[i][k][nn] + cost[k][j][nn]);
				}
			}
		}
	}
/*	for(nn = 1; nn <= n; nn++) {
		printf("%d\n", nn);
		for(i = 0; i < 3; i++) {
			for(j = 0; j < 3; j++) {
				printf("%3d", cost[i][j][nn]);
			}
			printf("\n");
		}
		printf("\n");
	}
*/
	myprint(cost[0][2][n]);
}

void myprint(long long n) {
	if(n > 0) {
		myprint(n/10);
		printf("%d", (int)(n%10));
	}
}

