fn main() {
    let mut sc = Scanner::new();
    let mut cost = vec![vec![0; 3]; 3];
    let mut memo = vec![vec![vec![0; 3]; 3]; 42];

    for i in 0..3 {
        for j in 0..3 {
            cost[i][j] = sc.cin::<i64>();
        }
    }

    for i in 0..3 {
        for j in 0..3 {
            if i == j { continue }
            let k = 3 - i - j;
            memo[1][i][j] = min(cost[i][k] + cost[k][j], cost[i][j]);
        }
    }

    let n: usize = sc.cin();

    for m in 2..(n+1) {
        for i in 0..3 {
            for j in 0..3 {
                if i == j { continue }
                let k = 3 - i - j;
                memo[m][i][j] =
                    min(
                    memo[m-1][i][k] + memo[m-1][k][j] + cost[i][j],
                    memo[m-1][i][j] + cost[i][k] + memo[m-1][j][i] + cost[k][j] + memo[m-1][i][j]);
            }
        }
